mapper.select:
SELECT a.id, a.subject AS title, a.visitor_company AS unit, a.industry, a.district, a.applicant, a.phone, a.applicant_dept AS dept, a.start_time AS startTime, a.end_time AS endTime, a.top_leader_title AS leader, a.visitor_count AS headCount, a.agenda, a.status, a.create_time AS created, v.actual_visit_count AS actualHeadCount, v.actual_visit_time AS actualVisitTime, v.opportunity_code AS opportunityCode, v.return_signer AS returnSigner, v.return_time AS returnTime, v.status AS visitStatus, COALESCE(p.photo_count, 0) AS photoCount FROM eh_apply a LEFT JOIN eh_visit_record v ON v.apply_id = a.id AND v.del_flag = '0' LEFT JOIN ( SELECT visit_id, COUNT(*) AS photo_count FROM eh_visit_photo WHERE del_flag = '0' GROUP BY visit_id ) p ON p.visit_id = v.id WHERE a.del_flag = '0'
AND a.status = #{status}
ORDER BY a.create_time DESC
